					tar.RemoveShip(shipID)
					*tar = saved
				}
			}
		}
		minDelta := 1e100
		chosenIdx := -1
		for _, bc := range bestList {
			if bc.delta < minDelta {
				minDelta = bc.delta
				chosenIdx = bc.assignIdx
			}
		}
		if chosenIdx >= 0 && chosenIdx < MAXASSIGNS {
			target := &dispatch.Assigns[chosenIdx]
			if target.AddShip(shipID, oris[idx], dess[idx]) {
				target.GenRoute()
				if target.Cost >= 0 {
					inserted = true
					if chosenIdx == dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
				} else {
					target.RemoveShip(shipID)
					target.GenRoute()
				}
			}
		}
		if !inserted {
			bestFallbackIdx := -1
			bestFallbackScore := 1e100
			for fi := 0; fi < dispatch.AssignsLen; fi++ {
				fr := &dispatch.Assigns[fi]
				if fr.Cost < 0 {
					continue
				}
				sv := *fr
				if fr.AddShip(shipID, oris[idx], dess[idx]) {
					fr.GenRoute()
					if fr.Cost >= 0 {
						fs := fr.Cost
						if fs < bestFallbackScore {
							bestFallbackScore = fs
							bestFallbackIdx = fi
						}
					}
				}
				*fr = sv
				fr.GenRoute()
			}
			if bestFallbackIdx >= 0 {
				frt := &dispatch.Assigns[bestFallbackIdx]
				svf := *frt
				if frt.AddShip(shipID, oris[idx], dess[idx]) {
					frt.GenRoute()
					if frt.Cost >= 0 {
						inserted = true
					} else {
						*frt = svf
						frt.GenRoute()
					}
				}
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			newr := &dispatch.Assigns[dispatch.AssignsLen]
			if newr.AddShip(shipID, oris[idx], dess[idx]) {
				newr.GenRoute()
				if newr.Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					newr.RemoveShip(shipID)
					newr.GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
